// ── Cell: 16-byte cache-line-friendly terminal cell ──────────────────────
pub const Cell = extern struct {
    char_bytes: [4]u8,  // UTF-8, null-padded
    char_len: u8,       // 1-4
    fg: [3]u8,          // RGB
    bg: [3]u8,          // RGB
    attrs: u8,          // bits: bold(0), italic(1), underline(2), strikethrough(3), dim(4), inverse(5)
    hit_id: u16,        // 0=none, 1..65535=mapped atom
    _pad: [2]u8,        // explicit padding to 16 bytes

    comptime {
        std.debug.assert(@sizeOf(Cell) == 16);
    }

    pub fn blank() Cell {
        return Cell{
            .char_bytes = [_]u8{ ' ', 0, 0, 0 },
            .char_len = 1,
            .fg = [_]u8{ 255, 255, 255 },
            .bg = [_]u8{ 0, 0, 0 },
            .attrs = 0,
            .hit_id = 0,
            ._pad = [_]u8{ 0, 0 },
        };
    }

    pub fn eql(a: Cell, b: Cell) bool {
        const a_bytes: *const [16]u8 = @ptrCast(&a);
        const b_bytes: *const [16]u8 = @ptrCast(&b);
        return std.mem.eql(u8, a_bytes, b_bytes);
    }
};

// ── FrameBuffer: double-buffered cell grid ───────────────────────────────
const FrameBufferData = struct {
    cols: u32,
    rows: u32,
    front: []Cell,
    back: []Cell,
};

pub const FrameBuffer = beam.Resource(FrameBufferData, root, .{});

fn alloc_cells(gpa: Allocator, count: usize) ![]Cell {
    const cells = try gpa.alloc(Cell, count);
    const b = Cell.blank();
    for (cells) |*c| {
        c.* = b;
    }
    return cells;
}

// ── NIF: init(cols, rows) → FrameBuffer resource ────────────────────────
pub fn init(cols: u32, rows: u32) !FrameBuffer {
    const gpa = beam.allocator;
    const count: usize = @as(usize, cols) * @as(usize, rows);
    const front = try alloc_cells(gpa, count);
    const back = try alloc_cells(gpa, count);

    return FrameBuffer.create(.{
        .cols = cols,
        .rows = rows,
        .front = front,
        .back = back,
    }, .{});
}

// ── NIF: clear(fb) → :ok ────────────────────────────────────────────────
pub fn clear(fb: FrameBuffer) void {
    const data = fb.unpack();
    const b = Cell.blank();
    for (data.back) |*c| {
        c.* = b;
    }
}

// ── NIF: get_cell_data(fb, x, y) → {char_bin, fg_r, fg_g, fg_b, bg_r, bg_g, bg_b, attrs, hit_id}
pub fn get_cell_data(fb: FrameBuffer, x: u32, y: u32) beam.term {
    const data = fb.unpack();
    if (x >= data.cols or y >= data.rows) {
        return beam.make(.nil, .{});
    }
    const idx = @as(usize, y) * @as(usize, data.cols) + @as(usize, x);
    const cell = data.front[idx];
    const char_slice = cell.char_bytes[0..cell.char_len];

    return beam.make(.{
        char_slice,
        @as(u8, cell.fg[0]),
        @as(u8, cell.fg[1]),
        @as(u8, cell.fg[2]),
        @as(u8, cell.bg[0]),
        @as(u8, cell.bg[1]),
        @as(u8, cell.bg[2]),
        cell.attrs,
        cell.hit_id,
    }, .{});
}

// ── NIF: put_cells(fb, binary) → :ok ────────────────────────────────────
// Batch binary protocol:
//   CELL: <<1, x::16-le, y::16-le, char[4], fg[3], bg[3], attrs, hit_id::16-le>> = 18 bytes
//   FILL: <<2, x::16-le, y::16-le, w::16-le, h::16-le, char[4], fg[3], bg[3], attrs>> = 20 bytes
//   HIT:  <<3, x::16-le, y::16-le, w::16-le, h::16-le, hit_id::16-le>> = 11 bytes
pub fn put_cells(fb: FrameBuffer, binary: []const u8) void {
    const data = fb.unpack();
    const cols = data.cols;
    const rows = data.rows;
    const back = data.back;
    var pos: usize = 0;

    while (pos < binary.len) {
        const tag = binary[pos];
        pos += 1;

        switch (tag) {
            1 => { // CELL: 17 bytes after tag
                if (pos + 17 > binary.len) return;
                const x = std.mem.readInt(u16, binary[pos..][0..2], .little);
                const y = std.mem.readInt(u16, binary[pos + 2..][0..2], .little);
                if (x < cols and y < rows) {
                    const idx = @as(usize, y) * @as(usize, cols) + @as(usize, x);
                    back[idx] = Cell{
                        .char_bytes = binary[pos + 4..][0..4].*,
                        .char_len = compute_char_len(binary[pos + 4..][0..4]),
                        .fg = binary[pos + 8..][0..3].*,
                        .bg = binary[pos + 11..][0..3].*,
                        .attrs = binary[pos + 14],
                        .hit_id = std.mem.readInt(u16, binary[pos + 15..][0..2], .little),
                        ._pad = [_]u8{ 0, 0 },
                    };
                }
                pos += 17;
            },
            2 => { // FILL: 19 bytes after tag
                if (pos + 19 > binary.len) return;
                const x = std.mem.readInt(u16, binary[pos..][0..2], .little);
                const y = std.mem.readInt(u16, binary[pos + 2..][0..2], .little);
                const w = std.mem.readInt(u16, binary[pos + 4..][0..2], .little);
                const h = std.mem.readInt(u16, binary[pos + 6..][0..2], .little);
                const char_bytes = binary[pos + 8..][0..4].*;
                const char_len = compute_char_len(&char_bytes);
                const fg = binary[pos + 12..][0..3].*;
                const bg = binary[pos + 15..][0..3].*;
                const attrs_val = binary[pos + 18];

                const cell = Cell{
                    .char_bytes = char_bytes,
                    .char_len = char_len,
                    .fg = fg,
                    .bg = bg,
                    .attrs = attrs_val,
                    .hit_id = 0,
                    ._pad = [_]u8{ 0, 0 },
                };

                var cy: u32 = y;
                while (cy < y + h and cy < rows) : (cy += 1) {
                    var cx: u32 = x;
                    while (cx < x + w and cx < cols) : (cx += 1) {
                        const idx = @as(usize, cy) * @as(usize, cols) + @as(usize, cx);
                        back[idx] = cell;
                    }
                }
                pos += 19;
            },
            3 => { // HIT: 10 bytes after tag
                if (pos + 10 > binary.len) return;
                const x = std.mem.readInt(u16, binary[pos..][0..2], .little);
                const y = std.mem.readInt(u16, binary[pos + 2..][0..2], .little);
                const w = std.mem.readInt(u16, binary[pos + 4..][0..2], .little);
                const h = std.mem.readInt(u16, binary[pos + 6..][0..2], .little);
                const hit_id = std.mem.readInt(u16, binary[pos + 8..][0..2], .little);

                var cy: u32 = y;
                while (cy < y + h and cy < rows) : (cy += 1) {
                    var cx: u32 = x;
                    while (cx < x + w and cx < cols) : (cx += 1) {
                        const idx = @as(usize, cy) * @as(usize, cols) + @as(usize, cx);
                        back[idx].hit_id = hit_id;
                    }
                }
                pos += 10;
            },
            else => return,
        }
    }
}

fn compute_char_len(bytes: *const [4]u8) u8 {
    if (bytes[0] == 0) return 1;
    var i: u8 = 4;
    while (i > 0) : (i -= 1) {
        if (bytes[i - 1] != 0) return i;
    }
    return 1;
}

// ── NIF: render_frame_capture(fb) → binary ──────────────────────────────
pub fn render_frame_capture(fb: FrameBuffer) ![]u8 {
    const gpa = beam.allocator;
    var data = fb.unpack();
    const cols = data.cols;
    const rows = data.rows;
    const count = @as(usize, cols) * @as(usize, rows);

    var output: ByteList = .{};
    defer output.deinit(gpa);

    var cur_fg: [3]u8 = [_]u8{ 255, 255, 255 };
    var cur_bg: [3]u8 = [_]u8{ 0, 0, 0 };
    var cur_attrs: u8 = 0;
    var sgr_initialized = false;

    var i: usize = 0;
    while (i < count) : (i += 1) {
        if (!Cell.eql(data.front[i], data.back[i])) {
            const x: u32 = @intCast(i % @as(usize, cols));
            const y: u32 = @intCast(i / @as(usize, cols));
            const cell = data.back[i];

            try write_cursor_move(gpa, &output, x + 1, y + 1);

            if (!sgr_initialized or
                !std.mem.eql(u8, &cur_fg, &cell.fg) or
                !std.mem.eql(u8, &cur_bg, &cell.bg) or
                cur_attrs != cell.attrs)
            {
                try write_sgr(gpa, &output, cell.fg, cell.bg, cell.attrs);
                cur_fg = cell.fg;
                cur_bg = cell.bg;
                cur_attrs = cell.attrs;
                sgr_initialized = true;
            }

            try output.appendSlice(gpa, cell.char_bytes[0..cell.char_len]);
        }
    }

    if (sgr_initialized) {
        try output.appendSlice(gpa, "\x1b[0m");
    }

    // Swap front and back, write back to resource
    const temp = data.front;
    data.front = data.back;
    data.back = temp;
    fb.update(data);

    // Return owned copy
    const result = try gpa.alloc(u8, output.items.len);
    @memcpy(result, output.items);
    return result;
}

