// ── NIF: resize(fb, cols, rows) → :ok ───────────────────────────────────
pub fn resize(fb: FrameBuffer, cols: u32, rows: u32) !void {
    const gpa = beam.allocator;
    var data = fb.unpack();
    const count = @as(usize, cols) * @as(usize, rows);

    gpa.free(data.front);
    gpa.free(data.back);

    data.front = try alloc_cells(gpa, count);
    data.back = try alloc_cells(gpa, count);
    data.cols = cols;
    data.rows = rows;
    fb.update(data);
}

// ── NIF: get_hit_id(fb, x, y) → u16 | nil ──────────────────────────────
pub fn get_hit_id(fb: FrameBuffer, x: u32, y: u32) beam.term {
    const data = fb.unpack();
    if (x >= data.cols or y >= data.rows) {
        return beam.make(.nil, .{});
    }
    const idx = @as(usize, y) * @as(usize, data.cols) + @as(usize, x);
    const hit = data.front[idx].hit_id;
    if (hit == 0) {
        return beam.make(.nil, .{});
    }
    return beam.make(hit, .{});
}

// ── NIF: to_strings(fb) → [String.t()] ─────────────────────────────────
pub fn to_strings(fb: FrameBuffer) !beam.term {
    const gpa = beam.allocator;
    const data = fb.unpack();
    const cols = data.cols;
    const rows = data.rows;

    var result_list: TermList = .{};
    defer result_list.deinit(gpa);

    var y: u32 = 0;
    while (y < rows) : (y += 1) {
        var row_buf: ByteList = .{};
        defer row_buf.deinit(gpa);

        var x: u32 = 0;
        while (x < cols) : (x += 1) {
            const idx = @as(usize, y) * @as(usize, cols) + @as(usize, x);
            const cell = data.front[idx];
            try row_buf.appendSlice(gpa, cell.char_bytes[0..cell.char_len]);
        }

        try result_list.append(gpa, beam.make(row_buf.items, .{}));
    }

    return beam.make(result_list.items, .{});
}

// ── NIF: draw_char_blend(fb, x, y, char[4], fg[3], bg[3]) → :ok ────────
pub fn draw_char_blend(fb: FrameBuffer, x: u32, y: u32, char_bytes: [4]u8, fg: [3]u8, bg: [3]u8) void {
    const data = fb.unpack();
    if (x >= data.cols or y >= data.rows) return;
    const idx = @as(usize, y) * @as(usize, data.cols) + @as(usize, x);
    data.back[idx] = Cell{
        .char_bytes = char_bytes,
        .char_len = compute_char_len(&char_bytes),
        .fg = fg,
        .bg = bg,
        .attrs = 0,
        .hit_id = data.back[idx].hit_id,
        ._pad = [_]u8{ 0, 0 },
    };
}

// ── ANSI helpers ────────────────────────────────────────────────────────
fn write_cursor_move(gpa: Allocator, output: *ByteList, x: u32, y: u32) !void {
    try output.appendSlice(gpa, "\x1b[");
    try write_u32(gpa, output, y);
    try output.append(gpa, ';');
    try write_u32(gpa, output, x);
    try output.append(gpa, 'H');
}

fn write_sgr(gpa: Allocator, output: *ByteList, fg: [3]u8, bg: [3]u8, attrs: u8) !void {
    try output.appendSlice(gpa, "\x1b[0");

    if (attrs & 1 != 0) try output.appendSlice(gpa, ";1");
    if (attrs & 16 != 0) try output.appendSlice(gpa, ";2");
    if (attrs & 2 != 0) try output.appendSlice(gpa, ";3");
    if (attrs & 4 != 0) try output.appendSlice(gpa, ";4");
    if (attrs & 32 != 0) try output.appendSlice(gpa, ";7");
    if (attrs & 8 != 0) try output.appendSlice(gpa, ";9");

    try output.appendSlice(gpa, ";38;2;");
    try write_u32(gpa, output, fg[0]);
    try output.append(gpa, ';');
    try write_u32(gpa, output, fg[1]);
    try output.append(gpa, ';');
    try write_u32(gpa, output, fg[2]);

    try output.appendSlice(gpa, ";48;2;");
    try write_u32(gpa, output, bg[0]);
    try output.append(gpa, ';');
    try write_u32(gpa, output, bg[1]);
    try output.append(gpa, ';');
    try write_u32(gpa, output, bg[2]);

    try output.append(gpa, 'm');
}

fn write_u32(gpa: Allocator, output: *ByteList, value: anytype) !void {
    var buf: [10]u8 = undefined;
    const v: u32 = @intCast(value);
    var len: usize = 0;

    if (v == 0) {
        try output.append(gpa, '0');
        return;
    }

    var n = v;
    while (n > 0) : (n /= 10) {
        buf[len] = @intCast(n % 10 + '0');
        len += 1;
    }

    var i: usize = 0;
    while (i < len) : (i += 1) {
        try output.append(gpa, buf[len - 1 - i]);
    }
}
